class $Gson$TypesTest {

  @Test
  void testGetMapKeyAndValueTypes_withProperties_returnsStringString() {
    Type[] result = $Gson$Types.getMapKeyAndValueTypes(Properties.class, Properties.class);
    assertNotNull(result);
    assertEquals(2, result.length);
    assertEquals(String.class, result[0]);
    assertEquals(String.class, result[1]);
  }

  @Test
  void testGetMapKeyAndValueTypes_withParameterizedMapType_returnsActualTypeArguments() throws Exception {
    // Prepare a ParameterizedType mock to be returned by getSupertype
    ParameterizedType parameterizedType = mock(ParameterizedType.class);
    Type keyType = String.class;
    Type valueType = Integer.class;
    when(parameterizedType.getActualTypeArguments()).thenReturn(new Type[] { keyType, valueType });

    try (MockedStatic<$Gson$Types> mockedStatic = Mockito.mockStatic($Gson$Types.class, Mockito.CALLS_REAL_METHODS)) {
      // Mock getSupertype to return our parameterizedType when called with the test inputs
      mockedStatic.when(() -> $Gson$Types.getSupertype(any(), any(), eq(Map.class))).thenReturn(parameterizedType);

      Type[] result = $Gson$Types.getMapKeyAndValueTypes(Object.class, Object.class);

      assertNotNull(result);
      assertEquals(2, result.length);
      assertEquals(keyType, result[0]);
      assertEquals(valueType, result[1]);
    }
  }

  @Test
  void testGetMapKeyAndValueTypes_withNonParameterizedMapType_returnsObjectObject() {
    try (MockedStatic<$Gson$Types> mockedStatic = Mockito.mockStatic($Gson$Types.class, Mockito.CALLS_REAL_METHODS)) {
      // Mock getSupertype to return a non-ParameterizedType (e.g. Class)
      mockedStatic.when(() -> $Gson$Types.getSupertype(any(), any(), eq(Map.class))).thenReturn((Type) Map.class);

      Type[] result = $Gson$Types.getMapKeyAndValueTypes(Object.class, Object.class);

      assertNotNull(result);
      assertEquals(2, result.length);
      assertEquals(Object.class, result[0]);
      assertEquals(Object.class, result[1]);
    }
  }
}
